const { exec } = require('child_process');
const { promisify } = require('util');
const fs = require('fs').promises;
const path = require('path');

const execAsync = promisify(exec);

const ALLOWED_FORMATS = new Set(['pdf', 'docx', 'odt', 'html', 'txt']);
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const TEMP_DIR = '/tmp';

module.exports = async function (context, req) {
    try {
        // Validate request body
        if (!req.body || !req.body.filename || !req.body.format) {
            context.res = {
                status: 400,
                body: "Missing required fields: filename and format"
            };
            return;
        }

        const { filename, format } = req.body;

        // Validate format
        if (!ALLOWED_FORMATS.has(format.toLowerCase())) {
            context.res = {
                status: 400,
                body: "Unsupported output format"
            };
            return;
        }

        // Validate filename (prevent path traversal)
        if (filename.includes('..') || filename.startsWith('/')) {
            context.res = {
                status: 400,
                body: "Invalid filename"
            };
            return;
        }

        // Validate file exists and is within allowed size
        const filePath = path.join(TEMP_DIR, filename);
        const stats = await fs.stat(filePath);
        if (stats.size > MAX_FILE_SIZE) {
            context.res = {
                status: 400,
                body: "File too large"
            };
            return;
        }

        // Generate output filename
        const outputFilename = filename.replace(/\.[^/.]+$/, `.${format}`);
        const outputPath = path.join(TEMP_DIR, outputFilename);

        // Execute LibreOffice conversion
        const command = `libreoffice --headless --convert-to ${format} --outdir ${TEMP_DIR} ${filePath}`;
        
        const result = await execAsync(command, { timeout: 30000 });
        
        // Read converted file
        const outputFile = await fs.readFile(outputPath, 'binary');
        
        // Clean up temporary files
        await fs.unlink(filePath);
        await fs.unlink(outputPath);
        
        context.res = {
            status: 200,
            headers: {
                'Content-Type': 'application/octet-stream',
                'Content-Disposition': `attachment; filename="${outputFilename}"`
            },
            body: outputFile
        };
        
    } catch (error) {
        context.log.error('Conversion error:', error);
        
        if (error.code === 'ETIMEDOUT' || error.message.includes('timeout')) {
            context.res = {
                status: 408,
                body: "Conversion timeout"
            };
        } else if (error.code === 'ENOENT') {
            context.res = {
                status: 404,
                body: "File not found"
            };
        } else {
            context.res = {
                status: 500,
                body: "Conversion failed"
            };
        }
    }
};